import{_ as t,c as i,o as r,ag as a}from"./chunks/framework.S-Qvb3wi.js";const h=JSON.parse('{"title":"DGrid Genesis Premium Incentive Mechanism & Rewards Explanation","description":"","frontmatter":{},"headers":[],"relativePath":"Incentive-Mechanism-&-Rewards.md","filePath":"Incentive-Mechanism-&-Rewards.md"}'),n={name:"Incentive-Mechanism-&-Rewards.md"};function s(o,e,d,l,c,u){return r(),i("div",null,e[0]||(e[0]=[a('<h1 id="dgrid-genesis-premium-incentive-mechanism-rewards-explanation" tabindex="-1">DGrid Genesis Premium Incentive Mechanism &amp; Rewards Explanation <a class="header-anchor" href="#dgrid-genesis-premium-incentive-mechanism-rewards-explanation" aria-label="Permalink to &quot;DGrid Genesis Premium Incentive Mechanism &amp; Rewards Explanation&quot;">​</a></h1><p>DGrid has tailored a long-term incentive system exclusively for Genesis Members, with $DGAI tokens as the core, to achieve value alignment between members and the ecosystem, allowing early supporters to fully share the generous dividends brought by network growth.</p><h3 id="core-incentives-genesis-co-building-rewards" tabindex="-1">Core Incentives: Genesis Co-Building Rewards <a class="header-anchor" href="#core-incentives-genesis-co-building-rewards" aria-label="Permalink to &quot;Core Incentives: Genesis Co-Building Rewards&quot;">​</a></h3><ul><li><strong>tDGAI &amp; IOTX Token Rewards</strong></li></ul><p>During the period of holding Genesis Premium status, members will automatically receive continuous tDGAI &amp; IOTX token rewards without any additional tasks. The total value of the rewards is closely tied to the activity level of the DGrid ecosystem, and will appreciate in tandem with the continuous growth of users, models, and computing tasks within the network, realizing the benefit of ​**&quot;passive income simply by holding Premium&quot;**​.</p><ul><li><strong>2% Referral Rebate Reward</strong></li></ul><p>Genesis Members are provided with exclusive referral links. After successfully inviting new users to purchase and activate Genesis Premium, the referrer will receive a 2% USDT rebate based on the new user’s purchase amount. Rebates will be credited automatically, and members can view records and withdraw funds in the <strong><a href="https://premium.dgrid.ai/referral" target="_blank" rel="noreferrer">Refer Friends</a></strong> section of the dashboard.</p><h3 id="tdgai-iotx-reward-redemption-tutorial" tabindex="-1">tDGAI &amp; IOTX Reward Redemption Tutorial <a class="header-anchor" href="#tdgai-iotx-reward-redemption-tutorial" aria-label="Permalink to &quot;tDGAI &amp; IOTX Reward Redemption Tutorial&quot;">​</a></h3><p>Genesis Members can conveniently redeem tDGAI and IOTX rewards through the DGrid Dashboard by following these steps:</p><ol><li>​<strong>Login Verification</strong>​: Log in to the official DGrid Dashboard using the wallet bound to your Genesis Pass, and complete wallet signature verification (no gas fee required).</li><li>​<strong>Access the &quot;Genesis Rewards&quot; Section</strong>​: Navigate to ​**&quot;My Rewards&quot;**​. The system will automatically display the redeemable amount of tDGAI and IOTX rewards. After verifying the details, click the <strong>&quot;Redeem&quot;</strong> button.</li><li>​<strong>Check Redemption Status</strong>​: Upon completion of the redemption operation, rewards will be distributed to your bound wallet. You can check the arrival status via the <strong>&quot;Redemption Records&quot;</strong> on the dashboard or your wallet explorer.</li></ol><blockquote><p>​<strong>Note</strong>​: tDGAI is the test version of DGAI tokens, which can be used to experience various functions on the DGrid test network. IOTX rewards are ecosystem synergy rewards, and can only be redeemed if your Genesis Premium status remains active.</p></blockquote>',11)]))}const p=t(n,[["render",s]]);export{h as __pageData,p as default};
